        sys.exit(0)
    sol = Solution()
    ans = sol.minBitFlips(a, b)
    print(ans)

solutions.cpp:
#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minBitFlips(int a, int b) {
        return __builtin_popcount(a ^ b);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    int a, b;
    if (!(cin >> a >> b)) return 0;
    Solution sol;
    int ans = sol.minBitFlips(a, b);
    cout << ans << endl;
    return 0;
}
